async function graphView(){title('Knowledge Graph','Triple-centric graph. Click entity to focus; click row for evidence.');W.innerHTML+='<div class="graph-controls"><select id="graph-case-filter"><option value="">All cases</option></select><input id="graph-search" placeholder="Search entities\u2026"><select id="graph-limit"><option value="30">Top 30</option><option value="50" selected>Top 50</option><option value="100">Top 100</option></select><button class="button" onclick="loadGraph()">Refresh</button><span id="graph-stats" class="meta"></span></div><div id="entity-focus-banner" class="entity-focus-banner" style="display:none"><span>Focused entity: <strong id="focus-label"></strong></span><button class="button-sm" onclick="clearEntityFocus()">Clear focus</button></div><div class="graph-layout" id="graph-layout"><div class="loading">Loading triples\u2026</div></div><div id="graph-detail" class="graph-detail-panel"></div>';var sel=document.querySelector('#graph-case-filter');sel.innerHTML='<option value="">All cases</option>'+cases.map(function(c){return'<option value="'+esc(c.case_id)+'">'+esc(c.case_id)+'</option>'}).join('');sel.onchange=function(){loadGraph()};document.querySelector('#graph-search').onkeydown=function(e){if(e.key==='Enter')loadGraph()};_focusedEntity=null;loadGraph()}
async function loadGraph(){var caseFilter=document.querySelector('#graph-case-filter')?document.querySelector('#graph-case-filter').value:'',searchQ=(document.querySelector('#graph-search')?document.querySelector('#graph-search').value:'').toLowerCase(),limit=parseInt(document.querySelector('#graph-limit')?document.querySelector('#graph-limit').value:'50'),params=new URLSearchParams({limit:String(Math.max(limit,150)),case_id:caseFilter});try{var triplesData=await api('/api/triples?'+params)}catch(e){document.querySelector('#graph-layout').innerHTML='<div class="empty">No display KG found. Please run system_b_build_clean_kg first.</div>';return}var triples=triplesData.items||[];if(triples.length===0){document.querySelector('#graph-layout').innerHTML='<div class="empty">No display KG found. Please run system_b_build_clean_kg first.</div>';return}triples=triples.filter(function(t){return isBiomedical(t.subject_display_label)&&isBiomedical(t.object_display_label)});if(searchQ){triples=triples.filter(function(t){return(t.subject_display_label||'').toLowerCase().indexOf(searchQ)>=0||(t.object_display_label||'').toLowerCase().indexOf(searchQ)>=0||(t.relation_normalized||'').toLowerCase().indexOf(searchQ)>=0})}triples=triples.slice(0,limit);_allGraphTriples=triples;_focusedEntity=null;var banner=document.querySelector('#entity-focus-banner');if(banner)banner.style.display='none';document.querySelector('#graph-stats').textContent=triples.length+' triples displayed';document.querySelector('#graph-detail').innerHTML='';renderFilteredTriples()}
